/**
 * @param {number[]} nums
 * @param {number} p
 * @param {number[][]} queries
 * @return {number}
 */
function solve(nums, p, queries) {
    const N = nums.length;
    const MAX_VAL = 50000;

    // --- Utility Functions ---

    function gcd(a, b) {
        while (b) {
            [a, b] = [b, a % b];
        }
        return a;
    }

    // Precompute smallest prime factors using Sieve up to MAX_VAL
    const spf = new Array(MAX_VAL + 1).fill(0);
    for (let i = 2; i <= MAX_VAL; i++) {
        if (spf[i] === 0) {
            spf[i] = i;
            for (let j = i * i; j <= MAX_VAL; j += i) {
                if (spf[j] === 0) {
                    spf[j] = i;
                }
            }
        }
    }

    // Function to get unique prime factors of a number k
    function getPrimeFactors(k) {
        const factors = new Set();
        while (k > 1) {
            const factor = spf[k];
            factors.add(factor);
            k /= factor;
        }
        return Array.from(factors);
    }

    // --- Initialization ---

    let totalK = 0;
    // Map to store counts: Prime -> Count of k's divisible by Prime
    const primeCounts = new Map();

    // Helper to update counts when k changes
    function updateCounts(k, delta) {
        if (k <= 0 || k > MAX_VAL) return;
        const factors = getPrimeFactors(k);
        for (const r of factors) {
            primeCounts.set(r, (primeCounts.get(r) || 0) + delta);
        }
    }

    // Initialize state
    for (let i = 0; i < N; i++) {
        const val = nums[i];
        if (val % p === 0) {
            const k = val / p;
            totalK++;
            updateCounts(k, 1);
        }
    }

    // --- Query Processing ---

    let goodSubsequenceCount = 0;

    // Function to check existence after update
    function checkExistence(currentNums) {
        if (N === 2) {
            // For N=2, good subsequence must have length 1.
            // Requires nums[i] == p for i=0 or i=1.
            return currentNums[0] === p || currentNums[1] === p;
        }

        // For N > 2, we check if GCD(K) == 1 and |K| >= 1.
        if (totalK === 0) {
            return false;
        }

        // Check if GCD(K) > 1. This happens if there is a prime r that divides ALL elements k in K.
        for (const count of primeCounts.values()) {
            if (count === totalK) {
                // Found a prime r that divides all k's. GCD(K) >= r > 1.
                return false;
            }
        }

        // If we reached here, GCD(K) = 1.
        // Since N > 2, if |K| >= 1, we found a solution. 
        // If |K| = N, since N >= 3 and GCD(K)=1, a proper subset of size < N exists with GCD 1.
        return true;
    }


    for (const [ind, val] of queries) {
        const oldVal = nums[ind];

        // 1. Handle removal of old value
        if (oldVal % p === 0) {
            const k_old = oldVal / p;
            totalK--;
            updateCounts(k_old, -1);
        }

        // 2. Handle addition of new value
        if (val % p === 0) {
            const k_new = val / p;
            totalK++;
            updateCounts(k_new, 1);
        }

        // 3. Perform update
        nums[ind] = val;

        // 4. Check condition
        if (checkExistence(nums)) {
            goodSubsequenceCount++;
        }
    }

    return goodSubsequenceCount;
}

