import scala.collection.mutable

object Solution {
  /**
   * Solves the good subsequence problem by tracking GCD properties of scaled elements (k = nums[i]/p).
   * 
   * @param nums The initial array of integers.
   * @param p The target GCD.
   * @param queries The list of updates.
   * @return The count of queries that result in the existence of a good subsequence.
   */
  def solve(nums: Array[Long]): Long, p: Long, queries: Array[Array[Long]]): Long = {
    val N = nums.length
    val MAX_VAL = 50000
    val P = p.toInt

    // --- Utility Functions ---

    def gcd(a: Int, b: Int): Int = {
      var x = a
      var y = b
      while (y != 0) {
        val temp = y
        y = x % y
        x = temp
      }
      x
    }

    // Precompute smallest prime factors (SPF) using Sieve up to MAX_VAL
    val spf = Array.fill(MAX_VAL + 1)(0)
    for (i <- 2 to MAX_VAL) {
      if (spf(i) == 0) {
        spf(i) = i
        var j = i * i
        while (j <= MAX_VAL) {
          if (spf(j) == 0) {
            spf(j) = i
          }
          j += i
        }
      }
    }

    // Function to get unique prime factors of a number k
    def getPrimeFactors(k: Int): Set[Int] = {
      val factors = new mutable.HashSet[Int]()
      var currentK = k
      while (currentK > 1) {
        val factor = spf(currentK)
        factors.add(factor)
        currentK /= factor
      }
      factors
    }

    // --- Initialization ---

    var totalK: Int = 0
    // Map to store counts: Prime -> Count of k's divisible by Prime
    val primeCounts = mutable.Map[Int, Int]()

    // Helper to update counts when k changes
    def updateCounts(k: Int, delta: Int): Unit = {
      if (k <= 0 || k > MAX_VAL) return
      val factors = getPrimeFactors(k)
      for (r <- factors) {
        primeCounts(r) = primeCounts.getOrElse(r, 0) + delta
      }
    }

    // Initialize state
    // We convert nums to a mutable array of Ints for faster access/manipulation internally, 
    // while respecting the input/output Long types.
    val currentNums = new Array[Int](N)
    for (i <- 0 until N) {
      val valLong = nums(i)
      val valInt = valLong.toInt
      currentNums(i) = valInt

      if (valInt % P == 0) {
        val k = valInt / P
        totalK += 1
        updateCounts(k, 1)
      }
    }

    // --- Query Processing ---

    var goodSubsequenceCount: Long = 0

    // Function to check existence after update
    def checkExistence(): Boolean = {
      if (N == 2) {
        // For N=2, good subsequence must have length 1. 
        // Requires nums[i] == p (i.e., k_i = 1) for i=0 or i=1.
        val k0 = if (currentNums(0) % P == 0) currentNums(0) / P else 0
        val k1 = if (currentNums(1) % P == 0) currentNums(1) / P else 0
        return k0 == 1 || k1 == 1
      }

      // For N > 2:
      if (totalK == 0) {
        return false
      }

      // Check if GCD(K) > 1. This happens if there is a prime r that divides ALL elements k in K.
      for ((_, count) <- primeCounts.toSeq) {
        if (count == totalK) {
          // Found a prime r that divides all k's. GCD(K) >= r > 1.
          return false
        }
      }

      // If we reached here, GCD(K) = 1. Since N > 2 and totalK >= 1, a good subsequence exists.
      return true
    }


    for (query <- queries) {
      val ind = query(0).toInt
      val newValLong = query(1)

      val oldValLong = nums(ind)
      val oldValInt = oldValLong.toInt
      val newValInt = newValLong.toInt

      // 1. Handle removal of old value
      if (oldValInt % P == 0) {
        val k_old = oldValInt / P
        totalK -= 1
        updateCounts(k_old, -1)
      }

      // 2. Handle addition of new value
      if (newValInt % P == 0) {
        val k_new = newValInt / P
        totalK += 1
        updateCounts(k_new, 1)
      }

      // 3. Perform update
      nums(ind) = newValLong
      currentNums(ind) = newValInt

      // 4. Check condition
      if (checkExistence()) {
        goodSubsequenceCount += 1
      }
    }

    goodSubsequenceCount
  }
}
