    const spf = new Array(MAX_VAL + 1).fill(0);
    for (let i = 2; i <= MAX_VAL; i++) {
        if (spf[i] === 0) {
            spf[i] = i;
            for (let j = i * i; j <= MAX_VAL; j += i) {
                if (spf[j] === 0) {
                    spf[j] = i;
                }
            }
        }
    }

    // Function to get unique prime factors of a number k
    function getPrimeFactors(k) {
        const factors = new Set();
        while (k > 1) {
            const factor = spf[k];
            factors.add(factor);
            k /= factor;
        }
        return Array.from(factors);
