    function updateCounts(k, delta) {
        if (k <= 0 || k > MAX_VAL) return;
        const factors = getPrimeFactors(k);
        for (const r of factors) {
            primeCounts.set(r, (primeCounts.get(r) || 0) + delta);
        }
